ProjectedActivityState SmartObjectRuntime::projectActivityElapsed(
    const ActivitySnapshot& activitySnapshot,
    float elapsedSeconds
);

// Input: unload snapshot activity block
//   activityId, smartObjectId, sequenceStep, startedAt,
//   plannedDurationSeconds, participants, activitySeed
//
// Output: ProjectedActivityState
//   phase: entering | in_progress | exiting | complete
//   sequenceStep, stepProgress (0..1)
//   role positions, facings, object overlay state
//   skipWalkIn: true when actors snap mid-activity
//
// Map spawns actors directly into this state.
// No replay of walk-to from zone spawn.

{
  "activityId": "ball_two_pokemon_pass",
  "elapsedProjectable": true,
  "sequence": [
    { "action": "walk_to_role_points", "phase": "entering", "durationSeconds": 4 },
    { "action": "face_each_other", "phase": "entering", "durationSeconds": 1 },
    { "action": "object_arc_between_roles", "phase": "in_progress", "durationSeconds": 3, "repeat": { "min": 3, "max": 8 } },
    { "action": "emote", "phase": "exiting", "durationSeconds": 2 }
  ],
  "lifecycle": {
    "onEnter": ["occupy_smart_object", "start_ball_overlay"],
    "onExit": ["release_roles", "stop_ball_overlay"],
    "onComplete": { "relationshipGain": 2, "memoryChance": 0.25 }
  }
}

